import * as stylex from "@stylexjs/stylex";
import type { BoxProps } from "../Box/box";
import { Box } from "../Box/box";
import {
  stackAlignStyles,
  stackDirectionStyles,
  stackGapStyles,
  stackJustifyStyles,
  stackWrapStyles,
} from "./stack.styles";

type StackDirection = keyof typeof stackDirectionStyles;
type StackGap = keyof typeof stackGapStyles;
type StackAlign = keyof typeof stackAlignStyles;
type StackJustify = keyof typeof stackJustifyStyles;

export type StackProps = Omit<BoxProps, "display"> & {
  direction?: StackDirection;
  gap?: StackGap;
  align?: StackAlign;
  justify?: StackJustify;
  wrap?: boolean;
};

export function Stack({
  direction,
  gap = "medium",
  align,
  justify,
  wrap,
  style,
  ...props
}: StackProps) {
  const resolvedDirection = direction ?? "column";
  const resolvedStyles = stylex.props(
    stackDirectionStyles[resolvedDirection],
    stackGapStyles[gap],
    align && stackAlignStyles[align],
    justify && stackJustifyStyles[justify],
    wrap && stackWrapStyles.true,
    style,
  );
  return <Box display="flex" {...resolvedStyles} {...props} />;
}

type VStackProps = Omit<StackProps, "direction">;

export function VStack(props: VStackProps) {
  return <Stack direction="column" {...props} />;
}

type HStackProps = Omit<StackProps, "direction">;

export function HStack(props: HStackProps) {
  return <Stack direction="row" {...props} />;
}

import * as stylex from "@stylexjs/stylex";
import { spacing } from "../../lib/theme/theme.stylex";

export const stackDirectionStyles = stylex.create({
  column: { flexDirection: "column" },
  row: { flexDirection: "row" },
});

export const stackGapStyles = stylex.create({
  none: { gap: 0 },
  xxsmall: { gap: spacing.xxsmall },
  xsmall: { gap: spacing.xsmall },
  small: { gap: spacing.small },
  medium: { gap: spacing.medium },
  large: { gap: spacing.large },
  xlarge: { gap: spacing.xlarge },
  xxlarge: { gap: spacing.xxlarge },
  xxxlarge: { gap: spacing.xxxlarge },
  huge: { gap: spacing.huge },
  massive: { gap: spacing.massive },
});

export const stackAlignStyles = stylex.create({
  start: { alignItems: "flex-start" },
  center: { alignItems: "center" },
  end: { alignItems: "flex-end" },
  stretch: { alignItems: "stretch" },
  baseline: { alignItems: "baseline" },
});

export const stackJustifyStyles = stylex.create({
  start: { justifyContent: "flex-start" },
  center: { justifyContent: "center" },
  end: { justifyContent: "flex-end" },
  between: { justifyContent: "space-between" },
  around: { justifyContent: "space-around" },
  evenly: { justifyContent: "space-evenly" },
  stretch: { justifyContent: "stretch" },
});

export const stackWrapStyles = stylex.create({
  true: { flexWrap: "wrap" },
});
